local p=game.Players.LocalPlayer local g=Instance.new("ScreenGui") g.Parent=p.PlayerGui local f=Instance.new("Frame") f.Parent=g f.Size=UDim2.new(0,200,0,150) f.Position=UDim2.new(0.5,-100,0.4,0) f.BackgroundColor3=Color3.fromRGB(20,20,30) f.BorderSizePixel=0 f.Active=true f.Draggable=true local t=Instance.new("TextLabel") t.Parent=f t.Size=UDim2.new(1,0,0,30) t.BackgroundColor3=Color3.fromRGB(0,180,0) t.Text="FARM" t.TextColor3=Color3.fromRGB(255,255,255) t.Font=Enum.Font.GothamBold t.TextSize=16 local b=Instance.new("TextButton") b.Parent=f b.Size=UDim2.new(0.8,0,0,35) b.Position=UDim2.new(0.1,0,0,40) b.BackgroundColor3=Color3.fromRGB(0,150,0) b.Text="ON" b.TextColor3=Color3.fromRGB(255,255,255) b.Font=Enum.Font.GothamBold b.TextSize=14 b.BorderSizePixel=0 local c=Instance.new("TextButton") c.Parent=f c.Size=UDim2.new(0.15,0,0,25) c.Position=UDim2.new(0.85,0,0,2) c.BackgroundColor3=Color3.fromRGB(200,40,40) c.Text="X" c.TextColor3=Color3.fromRGB(255,255,255) c.Font=Enum.Font.GothamBold c.TextSize=14 c.BorderSizePixel=0 local r=true b.MouseButton1Click:Connect(function() r=not r b.BackgroundColor3=r and Color3.fromRGB(0,150,0) or Color3.fromRGB(80,0,0) b.Text=r and "ON" or "OFF" end) c.MouseButton1Click:Connect(function() g:Destroy() end) spawn(function() while g and g.Parent do if r then for _,v in pairs(game:GetDescendants()) do if v:IsA("TextButton") and v.Visible and v.Active then local txt=string.lower(v.Text or "") if string.find(txt,"собрать") or string.find(txt,"harvest") or string.find(txt,"продать") or string.find(txt,"sell") or string.find(txt,"посадить") or string.find(txt,"plant") then pcall(function() v:Click() wait(0.3) end) end end end end wait(1) end end)
